mapper.select:
select
    ID as id,
    creator_employee_no as creatorEmployeeNo,
    Type_risk as typeRisk,
    Year_matriculation as yearMatriculation,
    Power as power,
    Cylinder_capacity as cylinderCapacity,
    Value_vehicle as valueVehicle,
    N_doors as nDoors,
    Type_fuel as typeFuel,
    Length as length,
    Weight as weight
from vehicle_info

    and ID = #{id}
    and creator_employee_no = #{creatorEmployeeNo}
    and Type_risk = #{typeRisk}
    and Power = #{power}
    and Cylinder_capacity = #{cylinderCapacity}
    and Value_vehicle = #{valueVehicle}
    and N_doors = #{nDoors}
    and Type_fuel = #{typeFuel}
    and Year_matriculation = #{yearMatriculation}
    and Length = #{length}
    and Weight = #{weight}

order by ID desc
